export class RecibeocComponent {
  constructor(svcRecibeoc, svcOC) {
    this.svcRecibeoc = svcRecibeoc;
    this.svcOC = svcOC;
    // ── Recepción OC ─────────────────────────────────────────────────────────
    this.folioRecibeoc = null;
    this.registros = [];
    this.cargandoRecibeoc = false;
    this.busquedaRecibeocHecha = false;
    this.registroEditando = null;
