      next: rows => {
        this.ordenesCompra = rows ?? [];
        this.cargandoOC = false;
        this.busquedaOCHecha = true;
      },
      error: () => {
        this.mostrarMensaje('Error al buscar Orden de Compra', 'error');
        this.cargandoOC = false;
        this.busquedaOCHecha = true;
      }
    });
  }
